import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel for matmul + dropout + mean + softmax
fused_kernel_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <curand_kernel.h>
#include <math.h>

__global__ void fused_matmul_dropout_mean_softmax_kernel(
    const float* input,
    const float* weight,
    const float* bias,
    float* output,
    int batch_size,
    int in_features,
    int out_features,
    float dropout_p,
    float dropout_scale,
    unsigned long long seed,
    bool training
) {
    int batch_idx = blockIdx.x;
    int out_idx = threadIdx.x;

    if (batch_idx >= batch_size || out_idx >= out_features) return;

    // Initialize random state
    curandStatePhilox4_32_10_t state;
    curand_init(seed, batch_idx * out_features + out_idx, 0, &state);

    // Perform matmul for this output feature
    float sum = 0.0f;
    const float* input_row = input + batch_idx * in_features;
    const float* weight_col = weight + out_idx * in_features;

    #pragma unroll 4
    for (int i = 0; i < in_features; i++) {
        sum += input_row[i] * weight_col[i];
    }

    // Add bias
    if (bias != nullptr) {
        sum += bias[out_idx];
    }

    // Apply dropout during training
    if (training && dropout_p > 0.0f) {
        float random_val = curand_uniform(&state);
        if (random_val < dropout_p) {
            sum = 0.0f;
        } else {
            sum *= dropout_scale;
        }
    }

    // Store intermediate result in shared memory for mean calculation
    extern __shared__ float shared_sum[];
    shared_sum[out_idx] = sum;
    __syncthreads();

    // Calculate mean across output features (reduction)
    if (out_idx == 0) {
        float mean_val = 0.0f;
        for (int i = 0; i < out_features; i++) {
            mean_val += shared_sum[i];
        }
        mean_val /= out_features;

        // Apply softmax (since we have only one value after mean, softmax becomes exp(mean)/exp(mean) = 1.0)
        // Actually, softmax over a single element is always 1.0
        output[batch_idx] = 1.0f;
    }
}

torch::Tensor fused_matmul_dropout_mean_softmax_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float dropout_p,
    bool training
) {
    auto batch_size = input.size(0);
    auto in_features = input.size(1);
    auto out_features = weight.size(0);

    // Create output tensor (batch_size, 1)
    auto output = torch::ones({batch_size, 1}, torch::TensorOptions().device(input.device()).dtype(input.dtype()));

    // Calculate dropout scale factor
    float dropout_scale = 1.0f / (1.0f - dropout_p);

    // Generate random seed
    unsigned long long seed = time(NULL);

    // Launch kernel with optimized configuration
    dim3 blocks(batch_size);
    int threads_count = (out_features < 1024) ? out_features : 1024;
    dim3 threads(threads_count);

    size_t shared_mem_size = threads_count * sizeof(float);

    fused_matmul_dropout_mean_softmax_kernel<<<blocks, threads, shared_mem_size>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        bias.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size,
        in_features,
        out_features,
        dropout_p,
        dropout_scale,
        seed,
        training
    );

    return output;
}
"""

fused_kernel_cpp_source = """
torch::Tensor fused_matmul_dropout_mean_softmax_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float dropout_p,
    bool training
);
"""

# Compile the inline CUDA code
fused_kernel = load_inline(
    name="fused_matmul_dropout_mean_softmax",
    cpp_sources=fused_kernel_cpp_source,
    cuda_sources=fused_kernel_source,
    functions=["fused_matmul_dropout_mean_softmax_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused CUDA kernel for matmul + dropout + mean + softmax.
    """
    def __init__(self, in_features, out_features, dropout_p):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.dropout_p = dropout_p

        # Initialize weights and bias
        self.weight = nn.Parameter(torch.Tensor(out_features, in_features))
        self.bias = nn.Parameter(torch.Tensor(out_features))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

        # Register the fused kernel
        self.fused_kernel = fused_kernel

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, in_features).

        Returns:
            torch.Tensor: Output tensor of shape (batch_size, 1).
        """
        return self.fused_kernel.fused_matmul_dropout_mean_softmax_cuda(
            x,
            self.weight,
            self.bias,
            self.dropout_p,
            self.training
        )

